create table podgroups
(
    id                  bigint unsigned auto_increment
        primary key,
    created_at          datetime(3)                    null,
    updated_at          datetime(3)                    null,
    deleted_at          datetime(3)                    null,
    name                varchar(255)                   not null comment 'PodGroup名称',
    namespace           varchar(255)                   not null comment '命名空间',
    instance_name       varchar(255)                   not null comment '关联的实例名称(Notebook/Training等)',
    instance_type       varchar(50)                    not null comment '实例类型(notebook/training/inference)',
    owner_id            bigint unsigned                not null comment '所属资源ID(NotebookID等)',
    owner_type          varchar(50)                    not null comment '所属资源类型',
    user_id             bigint unsigned                not null comment '用户ID',
    cluster_id          bigint unsigned                not null comment '集群ID',
    min_member          int         default 1          not null comment '最小成员数',
    queue               varchar(100)                   null comment '队列名称',
    priority_class_name varchar(100)                   null comment '优先级类名',
    phase               varchar(50)                    null comment '调度阶段(Pending/Running/Unknown)',
    status              varchar(50) default 'Creating' not null comment '状态(Creating/Running/Completed/Failed)',
    scheduled           int         default 0          null comment '已调度的Pod数量',
    running             int         default 0          null comment '运行中的Pod数量',
    succeeded           int         default 0          null comment '成功的Pod数量',
    failed              int         default 0          null comment '失败的Pod数量',
    cpu                 varchar(50)                    null comment 'CPU配置',
    memory              varchar(50)                    null comment '内存配置',
    gpu                 varchar(50)                    null comment 'GPU数量',
    gpu_model           varchar(100)                   null comment 'GPU型号',
    product_id          bigint unsigned                null comment '产品ID',
    order_id            bigint unsigned                null comment '订单ID',
    start_time          datetime(3)                    null comment '开始运行时间(用于计费)',
    end_time            datetime(3)                    null comment '结束时间(用于计费)',
    uid                 varchar(255)                   null comment 'K8s UID',
    resource_version    varchar(50)                    null comment '资源版本',
    generation          bigint                         null comment 'Generation',
    remark              text                           null comment '备注',
    constraint idx_name_namespace
        unique (name, namespace)
);

create index idx_podgroups_cluster_id
    on podgroups (cluster_id);

create index idx_podgroups_deleted_at
    on podgroups (deleted_at);

create index idx_podgroups_instance_name
    on podgroups (instance_name);

create index idx_podgroups_order_id
    on podgroups (order_id);

create index idx_podgroups_owner_id
    on podgroups (owner_id);

create index idx_podgroups_product_id
    on podgroups (product_id);

create index idx_podgroups_uid
    on podgroups (uid);

create index idx_podgroups_user_id
    on podgroups (user_id);

